class Student:
    def __init__(self, name, grade):
        self.name = name
        self.grade = grade
        self.marks = []

    def add_mark(self, score):
        self.marks.append(score)

    def average(self):
        return sum(self.marks) / len(self.marks)

asha = Student("Asha", 7)
asha.add_mark(92)
asha.add_mark(85)
asha.add_mark(78)

print(asha.marks)
print(asha.average())

